schema = "generator client {\n  provider = 'prisma-client-js'\n}\n\ndatasource db {\n  provider = 'postgresql'\n}\n\nmodel Cliente {\n  id        String          @id @default(cuid())\n  nome      String\n  telefone  String          @unique\n  criadoEm DateTime        @default(now())\n  pedidos   Pedido[]\n  ofertas   OfertaEnviada[]\n}\n\nmodel Categoria {\n  id       String    @id @default(cuid())\n  nome     String    @unique\n  ordem    Int       @default(0)\n  produtos Produto[]\n}\n\nmodel Produto {\n  id           String        @id @default(cuid())\n  nome         String\n  descricao    String?\n  preco        Float\n  disponivel   Boolean       @default(true)\n  categoriaId  String\n  categoria    Categoria     @relation(fields: [categoriaId], references: [id])\n  itensPedido  ItemPedido[]\n  receitaItens ReceitaItem[]\n}\n\nmodel Pedido {\n  id          String       @id @default(cuid())\n  clienteId   String\n  cliente     Cliente      @relation(fields: [clienteId], references: [id])\n  status      String       @default('PENDENTE')\n  total       Float\n  observacoes String?\n  criadoEm    DateTime     @default(now())\n  itens       ItemPedido[]\n}\n\nmodel ItemPedido {\n  id            String  @id @default(cuid())\n  pedidoId      String\n  pedido        Pedido  @relation(fields: [pedidoId], references: [id])\n  produtoId     String\n  produto       Produto @relation(fields: [produtoId], references: [id])\n  quantidade    Int\n  precoUnitario Float\n}\n\nmodel OfertaEnviada {\n  id        String   @id @default(cuid())\n  clienteId String\n  cliente   Cliente  @relation(fields: [clienteId], references: [id])\n  mensagem  String\n  enviadoEm DateTime @default(now())\n}\n\nmodel Insumo {\n  id            String                @id @default(cuid())\n  nome          String                @unique\n  unidade       String\n  estoqueAtual  Float                 @default(0)\n  estoqueMinimo Float                 @default(0)\n  custoMedio    Float                 @default(0)\n  receitaItens  ReceitaItem[]\n  movimentacoes MovimentacaoEstoque[]\n}\n\nmodel ReceitaItem {\n  id         String  @id @default(cuid())\n  produtoId  String\n  produto    Produto @relation(fields: [produtoId], references: [id])\n  insumoId   String\n  insumo     Insumo  @relation(fields: [insumoId], references: [id])\n  quantidade Float\n  unidade    String\n}\n\nmodel MovimentacaoEstoque {\n  id         String   @id @default(cuid())\n  insumoId   String\n  insumo     Insumo   @relation(fields: [insumoId], references: [id])\n  tipo       String\n  quantidade Float\n  motivo     String?\n  criadoEm   DateTime @default(now())\n}\n"
schema = schema.replace("'", '"')
with open('prisma/schema.prisma', 'w', encoding='utf-8', newline='\n') as f:
    f.write(schema)
print('Escrito OK')
with open('prisma/schema.prisma', 'rb') as f:
    inicio = f.read(3)
    print('Sem BOM - OK' if inicio != b'\xef\xbb\xbf' else 'AINDA TEM BOM')
